// Eleventy config. All pages are Nunjucks templates that render through
// _includes/base.njk (one <head>, one masthead component, one footer component,
// one nav in _data/nav.js). Output is pure static HTML to _site.
//
// The two email-preview pages are generated by the pipeline (not templated), so
// they pass through as-is. design/ and data/ are copied verbatim (the site fetches
// the JSON in data/ at runtime). We do NOT pass through the page *.html: they are
// built from the .njk, and any committed built copies at the root are ignored here
// (not templates, not passthrough) so there is never a collision.
module.exports = function (ec) {
  ec.addPassthroughCopy('design');
  ec.addPassthroughCopy('data');
  ec.addPassthroughCopy('email-preview.html');
  ec.addPassthroughCopy('weekly-sample.html');
  return {
    dir: { input: '.', output: '_site', includes: '_includes', data: '_data' },
    templateFormats: ['njk'],
  };
};
